  1→using System;
  2→using System.IO;
  3→using System.Text;
  4→using System.Text.RegularExpressions;
  5→
  6→namespace AssembleMonitor.Features.Communication;
  7→
  8→/// <summary>
  9→/// LS XGT FEnet 프로토콜 패킷 생성/파싱
 10→/// XGT 전용 프로토콜 (포트 2004)
 11→///
 12→/// 헤더 구조 (20바이트):
 13→/// [0-9]   CompanyID: "LSIS-XGT\0\0"
 14→/// [10-11] PLC Info
 15→/// [12]    CPU Info (0xA0 = XGI/XGR/XEC)
 16→/// [13]    Source of Frame (0x33=요청, 0x11=응답)
 17→/// [14-15] Invoke ID
 18→/// [16-17] Data Length (바이트 20 이후 길이)
 19→/// [18]    Slot/Position
 20→/// [19]    BCC
 21→///
 22→/// 애플리케이션 데이터 (20바이트~):
 23→/// [20-21] Command (0x0054=RSS, 0x0058=WSS)
 24→/// [22-23] Data Type (0x0014=WORD)
 25→/// [24-25] Reserved (0x0000) ← 필수!
 26→/// [26+]   데이터 프레임
 27→///
 28→/// 주소 변환 규칙 (XGT FEnet):
 29→/// - Word 읽기/쓰기 시 주소를 Byte 기반으로 변환
 30→/// - %MW100 → %MB200 (index×2), count도 BYTE 단위
 31→/// - %IW0.0.0 → %IB0.0.0, %QW → %QB 등
 32→/// </summary>
 33→public static class XgtProtocol
 34→{
 35→    // CompanyID (10바이트)
 36→    private static readonly byte[] COMPANY_ID =
 37→        [0x4C, 0x53, 0x49, 0x53, 0x2D, 0x58, 0x47, 0x54, 0x00, 0x00]; // "LSIS-XGT\0\0"
 38→
 39→    private const byte CPU_INFO = 0xA0;        // XGI/XGR/XEC
 40→    private const byte SOURCE_REQUEST = 0x33;   // PC → PLC
 41→    private const byte SOURCE_RESPONSE = 0x11;  // PLC → PC
 42→
 43→    // 명령어
 44→    private const ushort CMD_RSS_REQ = 0x0054;  // 연속 읽기 요청
 45→    private const ushort CMD_RSS_RSP = 0x0055;  // 연속 읽기 응답
 46→    private const ushort CMD_WSS_REQ = 0x0058;  // 연속 쓰기 요청
 47→    private const ushort CMD_WSS_RSP = 0x0059;  // 연속 쓰기 응답
 48→
 49→    // 데이터 타입
 50→    private const ushort DATA_TYPE_WORD = 0x0014;
 51→
 52→    // %MW100 → %MB200 변환 정규식 (M/D/L/K/F 영역)
 53→    private static readonly Regex RxWordAddr =
 54→        new(@"^%([MDLKF])W(\d+)$", RegexOptions.Compiled | RegexOptions.IgnoreCase);
 55→
 56→    // %IW0.0.0 → %IB0.0.0 / %QW0.0.0 → %QB0.0.0 / %UW0.9.1 → %UB0.9.2 변환
 57→    // dot notation: base.slot.offset — offset은 워드 단위이므로 ×2 필요
 58→    private static readonly Regex RxIoWordAddr =
 59→        new(@"^%([IQU])W(\d+\.\d+\.)(\d+)$", RegexOptions.Compiled | RegexOptions.IgnoreCase);
 60→
 61→    /// <summary>
 62→    /// Word 주소를 Byte 주소로 변환 (XGT FEnet 규칙)
 63→    /// %MW100 → %MB200, %UW0.9.0 → %UB0.9.0, %UW0.9.1 → %UB0.9.2
 64→    /// </summary>
 65→    private static string ConvertToByteAddress(string wordAddress)
 66→    {
 67→        // M/D/L/K/F 영역: %MW100 → %MB200 (index×2)
 68→        var m = RxWordAddr.Match(wordAddress);
 69→        if (m.Success)
 70→        {
 71→            var device = m.Groups[1].Value.ToUpper();
 72→            var index = int.Parse(m.Groups[2].Value);
 73→            return $"%{device}B{index * 2}";
 74→        }
 75→
 76→        // I/Q/U 영역: %UW0.9.1 → %UB0.9.2 (오프셋×2)
 77→        var m2 = RxIoWordAddr.Match(wordAddress);
 78→        if (m2.Success)
 79→        {
 80→            var device = m2.Groups[1].Value.ToUpper();
 81→            var prefix = m2.Groups[2].Value;   // "0.9."
 82→            var offset = int.Parse(m2.Groups[3].Value);
 83→            return $"%{device}B{prefix}{offset * 2}";
 84→        }
 85→
 86→        // 변환 불가 — 원본 그대로 반환
 87→        return wordAddress;
 88→    }
 89→
 90→    /// <summary>
 91→    /// 연속 WORD 읽기 요청 패킷 (RSS)
 92→    /// startAddress: %MW100 형태 → 내부에서 %MB200으로 변환
 93→    /// </summary>
 94→    public static byte[] BuildReadRequest(string startAddress, ushort wordCount)
 95→    {
 96→        var byteAddr = ConvertToByteAddress(startAddress);
 97→        var addrBytes = Encoding.ASCII.GetBytes(byteAddr);
 98→        var addrLen = (ushort)addrBytes.Length;
 99→        var byteCount = (ushort)(wordCount * 2);
100→
101→        // 데이터 프레임: Reserved(2) + 블록수(2) + 주소길이(2) + 주소(N) + 읽기BYTE수(2)
102→        var dataFrameLen = 2 + 2 + 2 + addrLen + 2;
103→
104→        return BuildPacket(CMD_RSS_REQ, dataFrameLen, writer =>
105→        {
106→            writer.Write((ushort)0x0000);   // Reserved (필수!)
107→            writer.Write((ushort)1);        // 블록 수
108→            writer.Write(addrLen);          // 주소 문자열 길이
109→            writer.Write(addrBytes);        // 주소 문자열 (BYTE 기반)
110→            writer.Write(byteCount);        // 읽을 BYTE 수
111→        });
112→    }
113→
114→    /// <summary>
115→    /// 연속 WORD 쓰기 요청 패킷 (WSS)
116→    /// startAddress: %MW200 형태 → 내부에서 %MB400으로 변환
117→    /// </summary>
118→    public static byte[] BuildWriteRequest(string startAddress, ushort[] values)
119→    {
120→        var byteAddr = ConvertToByteAddress(startAddress);
121→        var addrBytes = Encoding.ASCII.GetBytes(byteAddr);
122→        var addrLen = (ushort)addrBytes.Length;
123→        var wordCount = (ushort)values.Length;
124→        var byteCount = (ushort)(wordCount * 2);
125→
126→        // 데이터 프레임: Reserved(2) + 블록수(2) + 주소길이(2) + 주소(N) + BYTE수(2) + 데이터(N*2)
127→        var dataFrameLen = 2 + 2 + 2 + addrLen + 2 + byteCount;
128→
129→        return BuildPacket(CMD_WSS_REQ, dataFrameLen, writer =>
130→        {
131→            writer.Write((ushort)0x0000);   // Reserved (필수!)
132→            writer.Write((ushort)1);        // 블록 수
133→            writer.Write(addrLen);          // 주소 문자열 길이
134→            writer.Write(addrBytes);        // 주소 문자열 (BYTE 기반)
135→            writer.Write(byteCount);        // BYTE 수
136→            foreach (var val in values)
137→                writer.Write(val);
138→        });
139→    }
140→
141→    /// <summary>
142→    /// 응답 패킷 파싱 결과
143→    /// </summary>
144→    public record ParseResult(
145→        bool Success,
146→        ushort Command,
147→        ushort DataType,
148→        ushort[]? Words,
149→        string ErrorInfo);
150→
151→    /// <summary>
152→    /// 응답 패킷 파싱 (범용 — 읽기/쓰기 모두)
153→    /// 응답 구조: 헤더(20) + cmd(2) + dtype(2) + reserved(2) + status(2) + data
154→    /// </summary>
155→    public static ParseResult ParseResponse(byte[] response, int length)
156→    {
157→        // 최소 헤더(20) + cmd(2) + dtype(2) + reserved(2) + status(2) = 28바이트
158→        if (length < 28)
159→            return new(false, 0, 0, null,
160→                $"응답 너무 짧음: {length}B (최소 28B 필요)");
161→
162→        // 헤더 파싱 (20바이트 기준)
163→        var source = response[13];
164→        var dataLen = BitConverter.ToUInt16(response, 16);
165→        var command = BitConverter.ToUInt16(response, 20);
166→        var dataType = BitConverter.ToUInt16(response, 22);
167→        // [24-25] = Reserved, [26-27] = Status (스킵)
168→
169→        // 방향 확인
170→        if (source != SOURCE_RESPONSE)
171→            return new(false, command, dataType, null,
172→                $"응답 Source=0x{source:X2} (0x11 예상)");
173→
174→        // cmd(2) + dtype(2) + reserved(2) + status(2) 이후 = 바이트 28부터
175→        var appDataOffset = 28;
176→        var appDataLen = length - appDataOffset;
177→
178→        if (appDataLen < 2)
179→            return new(false, command, dataType, null,
180→                $"데이터 없음: cmd=0x{command:X4}, dataLen={dataLen}, total={length}B");
181→
182→        // 읽기 응답 (0x0055)
183→        if (command == CMD_RSS_RSP)
184→            return ParseReadData(response, length, appDataOffset);
185→
186→        // 쓰기 응답 (0x0059)
187→        if (command == CMD_WSS_RSP)
188→            return ParseWriteData(response, length, appDataOffset);
189→
190→        // 알 수 없는 명령
191→        return new(false, command, dataType, null,
192→            $"미지원 응답 cmd=0x{command:X4}");
193→    }
194→
195→    private static ParseResult ParseReadData(byte[] response, int length, int offset)
196→    {
197→        // [offset+0,1] = 블록 수
198→        var blockCount = BitConverter.ToUInt16(response, offset);
199→        offset += 2;
200→
201→        if (offset + 2 > length)
202→            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
203→                $"블록 수={blockCount}, 데이터 부족 ({length}B)");
204→
205→        // [offset+0,1] = 데이터 바이트 수
206→        var dataByteCount = BitConverter.ToUInt16(response, offset);
207→        offset += 2;
208→
209→        // 에러 체크: dataByteCount가 0xFFFF이면 에러 코드
210→        if (dataByteCount == 0xFFFF)
211→        {
212→            ushort errInfo = (offset + 2 <= length)
213→                ? BitConverter.ToUInt16(response, offset) : (ushort)0;
214→            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
215→                $"PLC 에러: code=0xFFFF, info=0x{errInfo:X4}");
216→        }
217→
218→        // 에러 체크: dataByteCount가 0이거나 비정상이면
219→        if (dataByteCount == 0 || offset + dataByteCount > length)
220→        {
221→            var remaining = length - offset + 2;
222→            var dump = BitConverter.ToString(response, offset - 2,
223→                Math.Min(remaining + 2, length - offset + 2));
224→            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
225→                $"블록={blockCount}, 데이터크기={dataByteCount}, 잔여={dump}");
226→        }
227→
228→        // WORD 배열 추출
229→        var wordCount = dataByteCount / 2;
230→        var words = new ushort[wordCount];
231→        for (int i = 0; i < wordCount; i++)
232→        {
233→            if (offset + 2 > length) break;
234→            words[i] = BitConverter.ToUInt16(response, offset);
235→            offset += 2;
236→        }
237→
238→        return new(true, CMD_RSS_RSP, DATA_TYPE_WORD, words, "OK");
239→    }
240→
241→    private static ParseResult ParseWriteData(byte[] response, int length, int offset)
242→    {
243→        if (offset + 2 > length)
244→            return new(false, CMD_WSS_RSP, DATA_TYPE_WORD, null,
245→                $"쓰기 응답 데이터 부족 ({length}B)");
246→
247→        var blockCount = BitConverter.ToUInt16(response, offset);
248→        return new(blockCount > 0, CMD_WSS_RSP, DATA_TYPE_WORD, null,
249→            blockCount > 0 ? "쓰기 OK" : "쓰기 실패 (block=0)");
250→    }
251→
252→    /// <summary>
253→    /// 응답 헤더를 사람이 읽을 수 있게 덤프
254→    /// </summary>
255→    public static string DumpResponseHeader(byte[] response, int length)
256→    {
257→        if (length < 20) return $"[헤더 부족: {length}B]";
258→
259→        var sb = new StringBuilder();
260→        var companyId = Encoding.ASCII.GetString(response, 0, 8).TrimEnd('\0');
261→        sb.Append($"ID={companyId}");
262→        sb.Append($" src=0x{response[13]:X2}");
263→        sb.Append($" len={BitConverter.ToUInt16(response, 16)}");
264→        if (length >= 22) sb.Append($" cmd=0x{BitConverter.ToUInt16(response, 20):X4}");
265→        if (length >= 24) sb.Append($" type=0x{BitConverter.ToUInt16(response, 22):X4}");
266→        return sb.ToString();
267→    }
268→
269→    private static byte[] BuildPacket(ushort command, int dataFrameLen,
270→        Action<BinaryWriter> writeDataFrame)
271→    {
272→        using var ms = new MemoryStream();
273→        using var writer = new BinaryWriter(ms);
274→
275→        // --- 헤더 (20바이트) ---
276→        writer.Write(COMPANY_ID);               // [0-9] "LSIS-XGT\0\0"
277→        writer.Write((ushort)0x0000);           // [10-11] PLC Info
278→        writer.Write(CPU_INFO);                 // [12] CPU Info
279→        writer.Write(SOURCE_REQUEST);           // [13] Source = 요청
280→        writer.Write((ushort)0x0000);           // [14-15] Invoke ID
281→
282→        // [16-17] Length = cmd(2) + dtype(2) + dataFrame (Reserved 포함)
283→        var appLen = (ushort)(4 + dataFrameLen);
284→        writer.Write(appLen);
285→
286→        writer.Write((byte)0x00);               // [18] Slot/Position
287→        writer.Write((byte)0x00);               // [19] BCC
288→
289→        // --- 애플리케이션 ---
290→        writer.Write(command);                  // [20-21] Command
291→        writer.Write(DATA_TYPE_WORD);           // [22-23] Data Type
292→
293→        // --- 데이터 프레임 (Reserved + block + addr + count) ---
294→        writeDataFrame(writer);
295→
296→        return ms.ToArray();
297→    }
298→}
