  1→using System;
  2→using System.Net.Sockets;
  3→using System.Threading;
  4→using System.Threading.Tasks;
  5→
  6→namespace AssembleMonitor.Features.Communication;
  7→
  8→/// <summary>
  9→/// XGT FEnet TCP 클라이언트
 10→/// 연결/읽기/쓰기 담당
 11→/// </summary>
 12→public class XgtClient : IDisposable
 13→{
 14→    private TcpClient? _tcp;
 15→    private NetworkStream? _stream;
 16→    private readonly SemaphoreSlim _lock = new(1, 1);
 17→
 18→    public string IpAddress { get; set; } = "192.168.0.50";
 19→    public int Port { get; set; } = 2004;
 20→    public int TimeoutMs { get; set; } = 3000;
 21→    public bool IsConnected => _tcp?.Connected == true;
 22→
 23→    /// <summary>
 24→    /// 통신 로그 콜백 (디버깅용)
 25→    /// </summary>
 26→    public Action<string>? OnLog { get; set; }
 27→
 28→    public async Task<bool> ConnectAsync()
 29→    {
 30→        try
 31→        {
 32→            Disconnect();
 33→            _tcp = new TcpClient();
 34→            _tcp.ReceiveTimeout = TimeoutMs;
 35→            _tcp.SendTimeout = TimeoutMs;
 36→
 37→            using var cts = new CancellationTokenSource(TimeoutMs);
 38→            await _tcp.ConnectAsync(IpAddress, Port, cts.Token);
 39→            _stream = _tcp.GetStream();
 40→            OnLog?.Invoke($"연결 성공: {IpAddress}:{Port}");
 41→            return true;
 42→        }
 43→        catch (Exception ex)
 44→        {
 45→            OnLog?.Invoke($"연결 실패: {ex.Message}");
 46→            Disconnect();
 47→            return false;
 48→        }
 49→    }
 50→
 51→    public void Disconnect()
 52→    {
 53→        _stream?.Dispose();
 54→        _tcp?.Dispose();
 55→        _stream = null;
 56→        _tcp = null;
 57→    }
 58→
 59→    /// <summary>
 60→    /// 연속 WORD 읽기
 61→    /// </summary>
 62→    public async Task<ushort[]?> ReadWordsAsync(string startAddress, ushort wordCount)
 63→    {
 64→        if (!IsConnected || _stream == null) return null;
 65→
 66→        await _lock.WaitAsync();
 67→        try
 68→        {
 69→            var request = XgtProtocol.BuildReadRequest(startAddress, wordCount);
 70→            LogBytes($"TX READ {startAddress} x{wordCount}", request, request.Length);
 71→            await _stream.WriteAsync(request);
 72→
 73→            var buffer = new byte[1024];
 74→            var bytesRead = await _stream.ReadAsync(buffer);
 75→            LogBytes($"RX READ {startAddress}", buffer, bytesRead);
 76→
 77→            if (bytesRead == 0)
 78→            {
 79→                OnLog?.Invoke("   → 수신 0바이트 (연결 끊김?)");
 80→                return null;
 81→            }
 82→
 83→            // 응답 헤더 덤프
 84→            OnLog?.Invoke($"   → 헤더: {XgtProtocol.DumpResponseHeader(buffer, bytesRead)}");
 85→
 86→            var result = XgtProtocol.ParseResponse(buffer, bytesRead);
 87→            if (result.Success)
 88→            {
 89→                LogWords($"   → 성공 {startAddress}", result.Words!);
 90→                return result.Words;
 91→            }
 92→            else
 93→            {
 94→                OnLog?.Invoke($"   → 실패: {result.ErrorInfo}");
 95→                return null;
 96→            }
 97→        }
 98→        catch (Exception ex)
 99→        {
100→            OnLog?.Invoke($"ERR READ {startAddress}: {ex.Message}");
101→            return null;
102→        }
103→        finally
104→        {
105→            _lock.Release();
106→        }
107→    }
108→
109→    /// <summary>
110→    /// 연속 WORD 쓰기
111→    /// </summary>
112→    public async Task<bool> WriteWordsAsync(string startAddress, ushort[] values)
113→    {
114→        if (!IsConnected || _stream == null) return false;
115→
116→        await _lock.WaitAsync();
117→        try
118→        {
119→            var request = XgtProtocol.BuildWriteRequest(startAddress, values);
120→            LogBytes($"TX WRITE {startAddress} x{values.Length}", request, request.Length);
121→            await _stream.WriteAsync(request);
122→
123→            var buffer = new byte[256];
124→            var bytesRead = await _stream.ReadAsync(buffer);
125→            LogBytes($"RX WRITE {startAddress}", buffer, bytesRead);
126→
127→            var result = XgtProtocol.ParseResponse(buffer, bytesRead);
128→            OnLog?.Invoke($"   → {result.ErrorInfo}");
129→            return result.Success;
130→        }
131→        catch (Exception ex)
132→        {
133→            OnLog?.Invoke($"ERR WRITE {startAddress}: {ex.Message}");
134→            return false;
135→        }
136→        finally
137→        {
138→            _lock.Release();
139→        }
140→    }
141→
142→    private void LogBytes(string label, byte[] data, int length)
143→    {
144→        if (OnLog == null) return;
145→        var hex = BitConverter.ToString(data, 0, Math.Min(length, 80)).Replace("-", " ");
146→        if (length > 80) hex += $" ...";
147→        OnLog($"[{DateTime.Now:HH:mm:ss.fff}] {label} [{length}B]: {hex}");
148→    }
149→
150→    private void LogWords(string label, ushort[] words)
151→    {
152→        if (OnLog == null) return;
153→        var hex = string.Join(" ", Array.ConvertAll(words, w => $"{w:X4}"));
154→        OnLog($"   {label}: [{words.Length}W] {hex}");
155→    }
156→
157→    public void Dispose()
158→    {
159→        Disconnect();
160→        _lock.Dispose();
161→    }
162→}
